import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./AdminDashboard.css";

const AdminDashboard = () => {
  const navigate = useNavigate();

  const [products, setProducts] = useState([]);
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activePage, setActivePage] = useState("");

  // ===== LOGOUT =====
  const logout = () => {
    localStorage.removeItem("adminToken");
    navigate("/admin/login");
  };

  // ===== FETCH DATA =====
  const fetchProducts = async () => {
    setLoading(true);
    setActivePage("products");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/products");
      setProducts(res.data);
    } catch {
      setProducts([]);
    }
    setLoading(false);
  };

  const fetchUsers = async () => {
    setLoading(true);
    setActivePage("users");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/users");
      setUsers(res.data);
    } catch {
      setUsers([]);
    }
    setLoading(false);
  };

  const fetchOrders = async () => {
    setLoading(true);
    setActivePage("orders");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/orders");
      setOrders(res.data);
    } catch {
      setOrders([]);
    }
    setLoading(false);
  };

  // ===== PRODUCT FORM =====
  const [newProduct, setNewProduct] = useState({
    name: "",
    price: "",
    stock: 0,
    category: "",
    image: null,
    preview: null,
  });

  const handleChange = (e) => {
    setNewProduct({ ...newProduct, [e.target.name]: e.target.value });
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setNewProduct({
      ...newProduct,
      image: file,
      preview: URL.createObjectURL(file),
    });
  };

  // ===== ADD PRODUCT =====
  const addProduct = async (e) => {
    e.preventDefault();

    const formData = new FormData();
    formData.append("name", newProduct.name);
    formData.append("price", newProduct.price);
    formData.append("stock", newProduct.stock);
    formData.append("category", newProduct.category);
    formData.append("image", newProduct.image);

    try {
      await axios.post(
        "http://localhost:5000/api/admin/products",
        formData,
        { headers: { "Content-Type": "multipart/form-data" } }
      );

      alert("Product added successfully");
      setNewProduct({
        name: "",
        price: "",
        stock: 0,
        category: "",
        image: null,
        preview: null,
      });

      fetchProducts();
    } catch (err) {
      alert("Failed to add product");
      console.error(err);
    }
  };

  const deleteProduct = async (id) => {
    if (!window.confirm("Delete this product?")) return;
    await axios.delete(`http://localhost:5000/api/admin/products/${id}`);
    fetchProducts();
  };

  // ===== PRODUCTS PAGE =====
  const ProductsPage = () => (
    <>
      <h2>Products</h2>

      <form className="product-form" onSubmit={addProduct}>
        <input
          type="text"
          name="name"
          placeholder="Product Name"
          value={newProduct.name}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="price"
          placeholder="Price (RM)"
          value={newProduct.price}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="stock"
          placeholder="Stock"
          value={newProduct.stock}
          onChange={handleChange}
        />

        <input
          type="text"
          name="category"
          placeholder="Category"
          value={newProduct.category}
          onChange={handleChange}
        />

        <input
          type="file"
          accept="image/*"
          onChange={handleImageChange}
          required
        />

        {newProduct.preview && (
          <img
            src={newProduct.preview}
            alt="Preview"
            className="image-preview"
          />
        )}

        <button type="submit">Add Product</button>
      </form>

      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Image</th>
            <th>Name</th>
            <th>Price</th>
            <th>Stock</th>
            <th>Category</th>
            <th>Action</th>
          </tr>
        </thead>
        <tbody>
          {products.map((p) => (
            <tr key={p.id}>
              <td>{p.id}</td>
              <td>
                <img
                  src={`http://localhost:5000/uploads/${p.image}`}
                  alt={p.name}
                  width="50"
                />
              </td>
              <td>{p.name}</td>
              <td>{p.price}</td>
              <td>{p.stock}</td>
              <td>{p.category}</td>
              <td>
                <button onClick={() => deleteProduct(p.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  // ===== USERS PAGE =====
  const UsersPage = () => (
    <>
      <h2>Users</h2>
      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Email</th>
          </tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.full_name}</td>
              <td>{u.email}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  // ===== ORDERS PAGE =====
  const OrdersPage = () => (
    <>
      <h2>Orders</h2>
      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>User</th>
            <th>Total</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {orders.map((o) => (
            <tr key={o.id}>
              <td>{o.id}</td>
              <td>{o.full_name}</td>
              <td>{o.total_amount}</td>
              <td>{o.payment_status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  return (
    <div className="admin-layout">
      <aside className="admin-sidebar">
        <h2 className="logo">ShopAdmin</h2>
        <button onClick={fetchProducts}>Products</button>
        <button onClick={fetchOrders}>Orders</button>
        <button onClick={fetchUsers}>Users</button>
        <button className="logout-btn" onClick={logout}>Logout</button>
      </aside>

      <main className="admin-content">
        {!activePage && <p>Welcome to Admin Dashboard</p>}
        {activePage === "products" && <ProductsPage />}
        {activePage === "users" && <UsersPage />}
        {activePage === "orders" && <OrdersPage />}
      </main>
    </div>
  );
};

export default AdminDashboard;
